CREATE OR REPLACE FUNCTION fpa_lon_calint_conno (as_conno char,adt_todate timestamp(0)) RETURNS bigint AS $body$
DECLARE

  ldc_bal bigint;
  ldc_int bigint;

BEGIN
  select principal_balance into STRICT ldc_bal
  from sc_lon_m_loan_card
  where (loan_contract_no = as_conno);
  if ldc_bal > 0 then
    CALL pka_lon_paysrv.sp_calint_spp(as_conno,adt_todate,ldc_bal,0);
    ldc_int := pka_lon_paysrv.fp_calint_value('intamt');
  end if;
  return coalesce(ldc_int,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
